/*
 * soldering_station.ino — Automatic Soldering Iron Station
 *
 * Elements:
 *   1. MAX31865 PT100 RTD   — SPI, tip temp at 10 Hz
 *   2. N-MOSFET load switch — D5, 10 Hz PWM duty cycle
 *   3. Rotary Encoder       — setpoint ±5 °C per detent
 *   4. SSD1306 OLED         — temp / setpoint / status
 *   5. Arduino Nano 3.0     — PID + auto-sleep
 */

#include <Wire.h>
#include <SPI.h>
#include <Adafruit_MAX31865.h>
#include <Adafruit_SSD1306.h>
#include <EEPROM.h>

// --- Pins ---
#define RTD_CS     10
#define HEAT_PIN    5
#define STAND_PIN   6   // reed switch: LOW = iron in stand
#define ENC_CLK     2
#define ENC_DT      4
#define ENC_SW      3

// --- PID tuning ---
#define KP 15.0f
#define KI  0.4f
#define KD  8.0f
#define PERIOD_MS  100UL   // 10 Hz
#define WINDOW_MS  100UL

// --- Sleep after idle ---
#define SLEEP_IDLE_MS (5UL * 60 * 1000)
#define SLEEP_TEMP_C  150.0f

// --- EEPROM ---
#define EE_SETPT 0

// --- Globals ---
Adafruit_MAX31865 rtd(RTD_CS);
Adafruit_SSD1306  oled(128, 64, &Wire, -1);

float setpoint    = 350.0f;
float actual      = 20.0f;
float i_term      = 0.0f;
float prev_err    = 0.0f;
float output      = 0.0f;
bool  sleeping    = false;
unsigned long last_activity = 0;

volatile int  enc_d = 0;
volatile bool enc_p = false;
void ICACHE_RAM_ATTR isr_clk() { enc_d += digitalRead(ENC_DT) ? -1 : 1; }
void ICACHE_RAM_ATTR isr_sw()  { enc_p = true; }

float run_pid(float sp, float pv, float dt) {
  float e = sp - pv;
  i_term   = constrain(i_term + KI * e * dt, 0.0f, 100.0f);
  float d  = (e - prev_err) / dt;
  prev_err = e;
  return constrain(KP * e + i_term + KD * d, 0.0f, 100.0f);
}

void update_oled(const char* status) {
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("Set: %3.0f C  Act: %3.0f C", setpoint, actual);
  oled.setCursor(0, 16); oled.print(status);
  oled.setCursor(0, 32); oled.printf("Power: %3.0f %%", output);
  int bar = (int)(output);
  oled.fillRect(0, 44, bar, 8, SSD1306_WHITE);
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin(); SPI.begin();

  rtd.begin(MAX31865_2WIRE);
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  // Load saved setpoint
  int16_t saved_sp;
  EEPROM.get(EE_SETPT, saved_sp);
  if (saved_sp >= 150 && saved_sp <= 480) setpoint = (float)saved_sp;

  pinMode(HEAT_PIN,  OUTPUT); digitalWrite(HEAT_PIN, LOW);
  pinMode(STAND_PIN, INPUT_PULLUP);
  pinMode(ENC_CLK, INPUT_PULLUP); pinMode(ENC_DT, INPUT_PULLUP); pinMode(ENC_SW, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_CLK), isr_clk, FALLING);
  attachInterrupt(digitalPinToInterrupt(ENC_SW),  isr_sw,  FALLING);

  last_activity = millis();
  Serial.println(F("Soldering station ready."));
}

void loop() {
  static unsigned long last_pid  = 0;
  static unsigned long win_start = 0;

  unsigned long now = millis();

  // --- Encoder ---
  noInterrupts(); int d = enc_d; enc_d = 0; bool p = enc_p; enc_p = false; interrupts();
  if (d != 0) {
    setpoint = constrain(setpoint + d * 5.0f, 150.0f, 480.0f);
    EEPROM.put(EE_SETPT, (int16_t)setpoint);
    last_activity = now;
    sleeping = false;
  }
  if (p) { sleeping = !sleeping; last_activity = now; }

  // Auto-sleep when iron in stand
  bool in_stand = !digitalRead(STAND_PIN);
  if (in_stand && (now - last_activity > SLEEP_IDLE_MS)) sleeping = true;
  if (!in_stand) last_activity = now;

  // --- PID at 10 Hz ---
  if (now - last_pid >= PERIOD_MS) {
    float dt = (now - last_pid) / 1000.0f;
    last_pid = now;

    // Median filter
    float s[3] = { rtd.temperature(100.0f, 430.0f),
                   rtd.temperature(100.0f, 430.0f),
                   rtd.temperature(100.0f, 430.0f) };
    // simple sort 3
    if (s[0] > s[1]) { float t = s[0]; s[0] = s[1]; s[1] = t; }
    if (s[1] > s[2]) { float t = s[1]; s[1] = s[2]; s[2] = t; }
    if (s[0] > s[1]) { float t = s[0]; s[0] = s[1]; s[1] = t; }
    actual = s[1];

    float eff_sp = sleeping ? SLEEP_TEMP_C : setpoint;
    output = run_pid(eff_sp, actual, dt);

    const char* status = sleeping   ? "SLEEP (150 C)" :
                         actual < setpoint - 10.0f ? "HEATING..." : "AT TEMP";
    update_oled(status);
    Serial.printf("T=%.1f SP=%.0f OUT=%.0f%s\n", actual, eff_sp, output, sleeping ? " [SLP]" : "");
  }

  // --- PWM window ---
  if (now - win_start >= WINDOW_MS) win_start = now;
  bool heat = (now - win_start) < (unsigned long)(output * WINDOW_MS / 100.0f);
  digitalWrite(HEAT_PIN, heat ? HIGH : LOW);
}
